import heapq

def johnsons(n, edges):
    """
    n     : vertices 0..n-1
    edges : list of (u, v, w)
    Returns all-pairs distance matrix, or None if negative cycle.
    """
    # Step 1: Bellman-Ford from virtual source (index n)
    dist_bf = [float('inf')] * (n + 1)
    dist_bf[n] = 0
    augmented = edges + [(n, v, 0) for v in range(n)]
    for _ in range(n):
        for u, v, w in augmented:
            if dist_bf[u] + w < dist_bf[v]:
                dist_bf[v] = dist_bf[u] + w
    # Negative cycle check
    for u, v, w in augmented:
        if dist_bf[u] + w < dist_bf[v]:
            return None
    h = dist_bf[:n]  # potentials

    # Step 2: Reweight edges
    adj = {i: [] for i in range(n)}
    for u, v, w in edges:
        w_prime = ___________        # non-negative reweighted weight
        adj[u].append((v, w_prime))

    # Step 3: Dijkstra from every source
    def dijkstra(src):
        d = [float('inf')] * n; d[src] = 0
        heap = [(0, src)]
        while heap:
            cost, u = heapq.heappop(heap)
            if cost > d[u]: continue
            for v, w in adj[u]:
                if d[u] + w < d[v]:
                    d[v] = d[u] + w
                    heapq.heappush(heap, (d[v], v))
        return d

    result = []
    for s in range(n):
        d = dijkstra(s)
        # Recover original distances
        result.append([d[t] - h[s] + h[t] if d[t] < float('inf') else float('inf') for t in range(n)])
    return result
